(function () {
  let initialized = false;

  function init() {
    if (initialized) return;
    initialized = true;

    const W = document.querySelector(".drive_slider");
    if (!W) return;

    const slides = [...W.querySelectorAll(".dss-slide")];
    const total = slides.length;

    if (!total) return;

    // Detectar slide activo REAL
    let cur = slides.findIndex(s =>
      s.classList.contains("dss-active")
    );

    if (cur === -1) cur = 0;

    // Preparar contenedor
    W.style.overflow = "hidden";
    W.style.position = "relative";
    W.style.width = "100%";

    // Normalizar TODOS los slides
    slides.forEach((slide, idx) => {
      slide.style.display = "block"; // <-- clave
      slide.style.width = "100%";
      slide.style.transition = "opacity .35s ease";

      if (idx === cur) {
        showSlide(slide);
      } else {
        hideSlide(slide);
      }
    });

    // Crear flechas
    let arrowBar = document.getElementById("dss-arrow-bar");

    if (!arrowBar) {
      arrowBar = document.createElement("div");
      arrowBar.id = "dss-arrow-bar";
      arrowBar.className = "drive_slider_arrows";

      arrowBar.innerHTML = `
        <div class="drive_slider_arrows_container">
          <div class="drive_slider_nav driver_slider_prev" id="dss-prev">
            ‹
          </div>
          <div class="drive_slider_nav driver_slider_next" id="dss-next">
            ›
          </div>
        </div>
      `;

      W.parentNode.insertBefore(
        arrowBar,
        W.nextSibling
      );
    }

    const prevBtn = document.getElementById("dss-prev");
    const nextBtn = document.getElementById("dss-next");

    function hideSlide(slide) {
      slide.style.position = "absolute";
      slide.style.top = "0";
      slide.style.left = "0";
      slide.style.opacity = "0";
      slide.style.visibility = "hidden";
      slide.style.pointerEvents = "none";
      slide.style.zIndex = "0";

      slide.classList.remove("dss-active");
    }

    function showSlide(slide) {
      slide.style.position = "relative";
      slide.style.opacity = "1";
      slide.style.visibility = "visible";
      slide.style.pointerEvents = "auto";
      slide.style.zIndex = "2";

      slide.classList.add("dss-active");
    }

    function updateButtons() {
      prevBtn.classList.toggle(
        "disabled",
        cur === 0
      );

      nextBtn.classList.toggle(
        "disabled",
        cur === total - 1
      );
    }

    function go(n) {
      if (n < 0 || n >= total) return;

      hideSlide(slides[cur]);

      cur = n;

      showSlide(slides[cur]);

      updateButtons();
    }

    prevBtn.addEventListener("click", () => {
      go(cur - 1);
    });

    nextBtn.addEventListener("click", () => {
      go(cur + 1);
    });

    updateButtons();
  }

  if (document.readyState === "loading") {
    document.addEventListener(
      "DOMContentLoaded",
      init
    );
  } else {
    init();
  }
})();